<style scoped lang="scss">
  @keyframes candle-to-blue {
    0%,
    100% {
      fill: #999999;
    }
    40%,
    60% {
      fill: #0051ff;
    }
  }

  @keyframes candle-to-orange {
    0%,
    100% {
      fill: #999999;
    }
    40%,
    60% {
      fill: #f75709;
    }
  }

  .candles path {
    animation-duration: 4s;
    animation-timing-function: ease-in-out;
    animation-iteration-count: infinite;
  }

  @for $i from 1 through 51 {
    .candles path:nth-child(#{$i}) {
      animation-name: if($i % 5 == 0, candle-to-orange, candle-to-blue);
      animation-delay: #{(51 - $i) * 0.08}s;
    }
  }
</style>
